import{_ as s,o as a,c as t,a2 as n}from"./chunks/framework.Wufm-cgV.js";const u=JSON.parse('{"title":"Session Memory Recall","description":"Automatic conversation context recovery with @recall","frontmatter":{"title":"Session Memory Recall","description":"Automatic conversation context recovery with @recall"},"headers":[],"relativePath":"guide/memory-recall.md","filePath":"guide/memory-recall.md"}'),i={name:"guide/memory-recall.md"};function o(r,e,l,d,p,c){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="session-memory-recall" tabindex="-1">Session Memory Recall <a class="header-anchor" href="#session-memory-recall" aria-label="Permalink to &quot;Session Memory Recall&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>When a client loses context — due to a restart, network interruption, or switching devices — WebRouter&#39;s session memory recall mechanism automatically recovers conversation history from the server and injects it back into the request.</p><p>No client-side storage needed. No complex state management. Just a simple trigger.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client disconnects</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ▼</span></span>
<span class="line"><span>┌─────────────┐     POST /v1/chat/completions     ┌──────────────┐</span></span>
<span class="line"><span>│   Client     │ ────────────────────────────────→ │   wr-proxy    │</span></span>
<span class="line"><span>│ (no history) │    @recall 还记得之前聊的...        │               │</span></span>
<span class="line"><span>└─────────────┘                                    └──────┬────────┘</span></span>
<span class="line"><span>                                                          │</span></span>
<span class="line"><span>                                                   ┌──────▼────────┐</span></span>
<span class="line"><span>                                                   │ wr_session_    │</span></span>
<span class="line"><span>                                                   │ messages       │</span></span>
<span class="line"><span>                                                   │ (SQLite)       │</span></span>
<span class="line"><span>                                                   └──────┬────────┘</span></span>
<span class="line"><span>                                                          │</span></span>
<span class="line"><span>                                                   ┌──────▼────────┐</span></span>
<span class="line"><span>                                                   │ Inject history │</span></span>
<span class="line"><span>                                                   │ into messages  │</span></span>
<span class="line"><span>                                                   │ (token budget  │</span></span>
<span class="line"><span>                                                   │  aware)        │</span></span>
<span class="line"><span>                                                   └──────┬────────┘</span></span>
<span class="line"><span>                                                          │</span></span>
<span class="line"><span>                                                          ▼</span></span>
<span class="line"><span>                                                    Upstream LLM</span></span></code></pre></div><h2 id="trigger-methods" tabindex="-1">Trigger Methods <a class="header-anchor" href="#trigger-methods" aria-label="Permalink to &quot;Trigger Methods&quot;">​</a></h2><h3 id="_1-recall-magic-word" tabindex="-1">1. <code>@recall</code> Magic Word <a class="header-anchor" href="#_1-recall-magic-word" aria-label="Permalink to &quot;1. \`@recall\` Magic Word&quot;">​</a></h3><p>Include <code>@recall</code> anywhere in your user message. wr-proxy detects it, strips it from the message, and injects the session history.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: @recall what was the third point from our earlier discussion?</span></span></code></pre></div><p>The <code>@recall</code> token is removed before the message reaches the upstream model.</p><h3 id="_2-natural-language-phrases" tabindex="-1">2. Natural Language Phrases <a class="header-anchor" href="#_2-natural-language-phrases" aria-label="Permalink to &quot;2. Natural Language Phrases&quot;">​</a></h3><p>For Chinese-language sessions, these phrases also trigger recall (when the client has no assistant messages in context):</p><table tabindex="0"><thead><tr><th>Phrase</th><th>Meaning</th></tr></thead><tbody><tr><td>还记得</td><td>Do you remember</td></tr><tr><td>继续上次</td><td>Continue from last time</td></tr><tr><td>继续聊</td><td>Keep chatting</td></tr><tr><td>接着说</td><td>Go on</td></tr><tr><td>之前聊过</td><td>We talked before</td></tr><tr><td>上次说到</td><td>Last time we mentioned</td></tr><tr><td>接着上次</td><td>Following up from last time</td></tr></tbody></table><h3 id="_3-http-header" tabindex="-1">3. HTTP Header <a class="header-anchor" href="#_3-http-header" aria-label="Permalink to &quot;3. HTTP Header&quot;">​</a></h3><p>Send <code>X-Recall-Session: &lt;session_id&gt;</code> to explicitly trigger recall for a specific session.</p><h2 id="token-budget-control" tabindex="-1">Token Budget Control <a class="header-anchor" href="#token-budget-control" aria-label="Permalink to &quot;Token Budget Control&quot;">​</a></h2><p>Recalled history is injected with a configurable token budget (default: 8000 tokens). wr-proxy accumulates messages from newest to oldest until the budget is exhausted, ensuring the most recent context is preserved.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Recent turns  ←  Injected first (within budget)</span></span>
<span class="line"><span>Old turns     ←  Omitted if budget exceeded</span></span>
<span class="line"><span>System prompt ←  Always preserved at top</span></span></code></pre></div><p>Configure via system setting <code>session_recall_budget</code>.</p><h2 id="session-message-storage" tabindex="-1">Session Message Storage <a class="header-anchor" href="#session-message-storage" aria-label="Permalink to &quot;Session Message Storage&quot;">​</a></h2><p>Every turn (user + assistant pair) is persisted asynchronously to <code>wr_session_messages</code>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>session_id</code></td><td>Unique session identifier (from <code>X-Session-Id</code> header)</td></tr><tr><td><code>token_id</code></td><td>Token that owns this session</td></tr><tr><td><code>turn_index</code></td><td>Monotonic turn number within the session</td></tr><tr><td><code>role</code></td><td><code>user</code> or <code>assistant</code></td></tr><tr><td><code>content</code></td><td>Message content (post-desensitization)</td></tr><tr><td><code>model</code></td><td>Model used for the assistant response</td></tr></tbody></table><h2 id="retention-policy" tabindex="-1">Retention Policy <a class="header-anchor" href="#retention-policy" aria-label="Permalink to &quot;Retention Policy&quot;">​</a></h2><p>Old sessions are automatically cleaned up based on <code>session_recall_retention_days</code> (default: 30 days). The cleanup runs every 6 hours.</p><h2 id="enabling-session-recall" tabindex="-1">Enabling Session Recall <a class="header-anchor" href="#enabling-session-recall" aria-label="Permalink to &quot;Enabling Session Recall&quot;">​</a></h2><p>Per token configuration:</p><ol><li>Go to <strong>Tokens</strong> → select a token</li><li>Enable <strong>Session Recall</strong></li><li>Client must send <code>X-Session-Id</code> header with requests</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5051/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;token&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;X-Session-Id: my-session-001&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;model&quot;: &quot;gpt-4o&quot;, &quot;messages&quot;: [{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;@recall continue our discussion&quot;}]}&#39;</span></span></code></pre></div><h2 id="architecture-notes" tabindex="-1">Architecture Notes <a class="header-anchor" href="#architecture-notes" aria-label="Permalink to &quot;Architecture Notes&quot;">​</a></h2><ul><li><strong>Async persistence</strong>: Messages are written via a buffered channel + single goroutine worker, ensuring zero latency impact on request forwarding</li><li><strong>Desensitization-first</strong>: Content is stored after desensitization rules are applied</li><li><strong>Token isolation</strong>: Each token&#39;s sessions are strictly isolated — no cross-token recall</li><li><strong>Multi-turn integrity</strong>: Turn index is assigned sequentially per session to prevent ordering issues</li></ul>`,31)])])}const g=s(i,[["render",o]]);export{u as __pageData,g as default};
